import org.junit.Test
import kotlin.test.*

class YieldEventLoopTest : TestBase() {
    @Test
    fun testYieldToDelayedTask() = runBlocking {
        var firstRan = false
        launch {
            delay(1)
            firstRan = true
            println("This should be first")
        }
        Thread.sleep(100) // wait for delay to expire
        yield()
        assertTrue(firstRan, "Yield should have resumed the delayed coroutine")
        println("This should be second")
    }

    @Test
    fun testYieldToDelayedTaskUndispatched() = runBlocking {
        var firstRan = false
        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            firstRan = true
            println("This should be first")
        }
        Thread.sleep(100) // wait for delay to expire
        yield()
        assertTrue(firstRan, "Yield should have resumed the delayed coroutine")
        println("This should be second")
    }
}
